def findMin(nums):
    l, r = 0, len(nums) - 1
    while l < r:
        mid = l + (r - l) // 2
        if nums[mid] > nums[r]:
            # Min is in the right unsorted part
            l = mid + 1
        else:
            # Min is at mid or to the left
            r = mid
    return nums[l]

