def findMedianSortedArrays(nums1, nums2):
    A, B = nums1, nums2
    if len(A) > len(B):
        A, B = B, A # Ensure A is the smaller array

    total = len(A) + len(B)
    half = (total + 1) // 2

    l, r = 0, len(A)
    while l <= r:
        i = l + (r - l) // 2 # Partition index in A
        j = half - i         # Partition index in B

        leftA = A[i - 1] if i > 0 else float('-inf')
        rightA = A[i] if i < len(A) else float('inf')
        leftB = B[j - 1] if j > 0 else float('-inf')
        rightB = B[j] if j < len(B) else float('inf')

        # Partition is correct
        if leftA <= rightB and leftB <= rightA:
            # Odd total length
            if total % 2:
                return max(leftA, leftB)
            # Even total length
            return (max(leftA, leftB) + min(rightA, rightB)) / 2.0
        elif leftA > rightB:
            r = i - 1 # Too many elements on left of A
        else:
            l = i + 1 # Too few elements on left of A
    return 0.0

cppCode:
double findMedianSortedArrays(vector<int>& nums1, vector<int>& nums2) {
    vector<int>& A = nums1;
    vector<int>& B = nums2;
    if (A.size() > B.size()) {
        return findMedianSortedArrays(nums2, nums1);
    }
    int m = A.size(), n = B.size();
    int total = m + n;
    int half = (total + 1) / 2;

    int l = 0, r = m;
    while (l <= r) {
        int i = l + (r - l) / 2;
        int j = half - i;

        int leftA = (i > 0) ? A[i - 1] : INT_MIN;
        int rightA = (i < m) ? A[i] : INT_MAX;
        int leftB = (j > 0) ? B[j - 1] : INT_MIN;
        int rightB = (j < n) ? B[j] : INT_MAX;

        if (leftA <= rightB && leftB <= rightA) {
            if (total % 2 != 0) {
                return max(leftA, leftB);
            }
            return (max(leftA, leftB) + min(rightA, rightB)) / 2.0;
        } else if (leftA > rightB) {
            r = i - 1;
        } else {
            l = i + 1;
        }
    }
    return 0.0;
}

