def splitArray(nums, k):
    # Helper to check if maximum sum target is feasible with k splits
    def can_partition(max_sum):
        subarrays = 1
        curr_sum = 0
        for num in nums:
            if curr_sum + num > max_sum:
                subarrays += 1
                curr_sum = num
                if subarrays > k:
                    return False
            else:
                curr_sum += num
        return True

    l, r = max(nums), sum(nums)
    res = r
    while l <= r:
        mid = l + (r - l) // 2
        if can_partition(mid):
            res = mid
            r = mid - 1 # Try to find a smaller maximum sum
        else:
            l = mid + 1 # Target sum too small, need larger limits
    return res

