int splitArray(vector<int>& nums, int k) {
    long long l = 0, r = 0;
    for (int num : nums) {
        l = max(l, (long long)num);
        r += num;
    }

    auto can_partition = [&](long long max_sum) -> bool {
        int subarrays = 1;
        long long curr_sum = 0;
        for (int num : nums) {
            if (curr_sum + num > max_sum) {
                subarrays++;
                curr_sum = num;
                if (subarrays > k) return false;
            } else {
                curr_sum += num;
            }
        }
        return true;
    };

    long long res = r;
    while (l <= r) {
        long long mid = l + (r - l) / 2;
        if (can_partition(mid)) {
            res = mid;
            r = mid - 1;
        } else {
            l = mid + 1;
        }
    }
    return res;
}

